mapper.select:
SELECT id, chat_room_id, user_id, last_read_message_id, last_read_at, joined_at, left_at
FROM chat_room_members
WHERE chat_room_id = #{chatRoomId}
  AND user_id = #{userId}

mapper.update:
UPDATE chat_room_members
SET last_read_message_id = #{lastReadMessageId},
    last_read_at = #{lastReadAt}
WHERE chat_room_id = #{chatRoomId}
  AND user_id = #{userId}
  AND #{lastReadMessageId} IS NOT NULL
  AND (
      last_read_message_id IS NULL
      OR last_read_message_id < #{lastReadMessageId}
  )

UPDATE chat_room_members
SET left_at = #{leftAt}
WHERE chat_room_id = #{chatRoomId}
  AND user_id = #{userId}

UPDATE chat_room_members
SET left_at = NULL,
    joined_at = #{joinedAt}
WHERE chat_room_id = #{chatRoomId}
  AND user_id = #{userId}
